@using sv_67b0a31f79bf45758e9a29e245d4ebb7.Components.Pages.ApplySteps

<nav aria-label="Application steps" class="mb-3">
    <ol class="d-flex list-unstyled justify-content-between p-0 m-0">
        @foreach (var (name, index) in _steps)
        {
            var step = index;
            var isCompleted = CompletedSteps.Contains(step);
            var isCurrent = step == CurrentStep;
            var isClickable = isCompleted && !isCurrent;

            <li class="text-center flex-fill position-relative" style="min-width: 0;">
                <button type="button"
                        class="btn btn-link text-decoration-none p-0 w-100 @(isClickable ? "" : "pe-none")"
                        disabled="@(!isClickable)"
                        @onclick="() => OnStepClicked.InvokeAsync(step)">
                    <span class="d-inline-flex align-items-center justify-content-center rounded-circle mb-1 @StepBadgeClass(isCurrent, isCompleted)"
                          style="width: 32px; height: 32px; font-size: 0.85rem;">
                        @if (isCompleted && !isCurrent)
                        {
                            <span>✓</span>
                        }
                        else
                        {
                            @step
                        }
                    </span>
                    <br />
                    <small class="@StepTextClass(isCurrent, isCompleted)">@name</small>
                </button>
            </li>
        }
    </ol>
</nav>

@code {
    [Parameter, EditorRequired] public int CurrentStep { get; set; }
    [Parameter, EditorRequired] public HashSet<int> CompletedSteps { get; set; } = new();
    [Parameter] public EventCallback<int> OnStepClicked { get; set; }

    private static readonly (string Name, int Index)[] _steps =
    [
        ("Personal Info", 1),
        ("Work History", 2),
        ("References", 3),
        ("Cover Letter", 4),
        ("Review & Submit", 5)
    ];

    private static string StepBadgeClass(bool isCurrent, bool isCompleted) =>
        isCurrent ? "bg-primary text-white"
        : isCompleted ? "bg-success text-white"
        : "bg-light text-muted border";

    private static string StepTextClass(bool isCurrent, bool isCompleted) =>
        isCurrent ? "text-primary fw-semibold"
        : isCompleted ? "text-success"
        : "text-muted";
}

@using sv_67b0a31f79bf45758e9a29e245d4ebb7.Components.Pages.ApplySteps

<h4 class="card-title mb-3">Personal Information</h4>

<div class="mb-3">
    <label class="form-label">Full Name <span class="text-danger">*</span></label>
    <input type="text" class="form-control" value="@FullName"
           @oninput="e => FullNameChanged.InvokeAsync(e.Value?.ToString() ?? "")" />
</div>

<div class="mb-3">
    <label class="form-label">Email <span class="text-danger">*</span></label>
    <input type="email" class="form-control" value="@Email"
           @oninput="e => EmailChanged.InvokeAsync(e.Value?.ToString() ?? "")" />
</div>

<div class="mb-3">
    <label class="form-label">Phone <span class="text-danger">*</span></label>
    <input type="tel" class="form-control" value="@Phone"
           @oninput="e => PhoneChanged.InvokeAsync(e.Value?.ToString() ?? "")" />
</div>

<div class="mb-3">
    <label class="form-label">Address <span class="text-danger">*</span></label>
    <textarea class="form-control" rows="2" @oninput="e => AddressChanged.InvokeAsync(e.Value?.ToString() ?? "")">@Address</textarea>
</div>

@if (!string.IsNullOrEmpty(ValidationError))
{
    <div class="alert alert-danger py-2">@ValidationError</div>
}

<div class="d-flex justify-content-end">
    <button class="btn btn-primary" @onclick="OnNext">Next →</button>
</div>

@code {
    [Parameter] public string FullName { get; set; } = "";
    [Parameter] public EventCallback<string> FullNameChanged { get; set; }

    [Parameter] public string Email { get; set; } = "";
    [Parameter] public EventCallback<string> EmailChanged { get; set; }

    [Parameter] public string Phone { get; set; } = "";
    [Parameter] public EventCallback<string> PhoneChanged { get; set; }

    [Parameter] public string Address { get; set; } = "";
    [Parameter] public EventCallback<string> AddressChanged { get; set; }

    [Parameter] public string? ValidationError { get; set; }
    [Parameter] public EventCallback OnNext { get; set; }
}

@using sv_67b0a31f79bf45758e9a29e245d4ebb7.Components.Pages.ApplySteps

<h4 class="card-title mb-3">Work History</h4>

@for (int i = 0; i < WorkEntries.Count; i++)
{
    var index = i;
    var entry = WorkEntries[index];

    <div class="border rounded p-3 mb-3">
        <div class="d-flex justify-content-between align-items-center mb-2">
            <h6 class="mb-0">Position @(index + 1)</h6>
            @if (WorkEntries.Count > 1)
            {
                <button class="btn btn-outline-danger btn-sm" @onclick="() => RemoveEntry(index)">Remove</button>
            }
        </div>

        <div class="row mb-2">
            <div class="col-md-6">
                <label class="form-label">Company <span class="text-danger">*</span></label>
                <input type="text" class="form-control" @bind="entry.Company" />
            </div>
            <div class="col-md-6">
                <label class="form-label">Job Title <span class="text-danger">*</span></label>
                <input type="text" class="form-control" @bind="entry.Title" />
            </div>
        </div>

        <div class="row mb-2">
            <div class="col-md-4">
                <label class="form-label">Start Date <span class="text-danger">*</span></label>
                <input type="date" class="form-control" @bind="entry.StartDate" />
            </div>
            <div class="col-md-4">
                <label class="form-label">End Date</label>
                <input type="date" class="form-control" @bind="entry.EndDate" disabled="@entry.IsCurrent" />
            </div>
            <div class="col-md-4 d-flex align-items-end pb-1">
                <div class="form-check">
                    <input class="form-check-input" type="checkbox" id="current-@index" @bind="entry.IsCurrent" />
                    <label class="form-check-label" for="current-@index">Currently working here</label>
                </div>
            </div>
        </div>

        <div class="mb-2">
            <label class="form-label">Description</label>
            <textarea class="form-control" rows="2" @bind="entry.Description"></textarea>
        </div>
    </div>
}

<button class="btn btn-outline-secondary btn-sm mb-3" @onclick="AddEntry">
    + Add Another Position
</button>

@if (!string.IsNullOrEmpty(ValidationError))
{
    <div class="alert alert-danger py-2">@ValidationError</div>
}

<div class="d-flex justify-content-between">
    <button class="btn btn-outline-secondary" @onclick="OnBack">← Back</button>
    <button class="btn btn-primary" @onclick="OnNext">Next →</button>
</div>

@code {
    [Parameter, EditorRequired] public List<WorkEntryModel> WorkEntries { get; set; } = new();
    [Parameter] public string? ValidationError { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }
    [Parameter] public EventCallback OnNext { get; set; }

    private void AddEntry() => WorkEntries.Add(new WorkEntryModel());

    private void RemoveEntry(int index) => WorkEntries.RemoveAt(index);
}

@using sv_67b0a31f79bf45758e9a29e245d4ebb7.Components.Pages.ApplySteps

<h4 class="card-title mb-3">References</h4>

@for (int i = 0; i < References.Count; i++)
{
    var index = i;
    var r = References[index];

    <div class="border rounded p-3 mb-3">
        <div class="d-flex justify-content-between align-items-center mb-2">
            <h6 class="mb-0">Reference @(index + 1)</h6>
            @if (References.Count > 2)
            {
                <button class="btn btn-outline-danger btn-sm" @onclick="() => RemoveReference(index)">Remove</button>
            }
        </div>

        <div class="row mb-2">
            <div class="col-md-6">
                <label class="form-label">Name <span class="text-danger">*</span></label>
                <input type="text" class="form-control" @bind="r.Name" />
            </div>
            <div class="col-md-6">
                <label class="form-label">Relationship</label>
                <input type="text" class="form-control" @bind="r.Relationship" />
            </div>
        </div>

        <div class="row mb-2">
            <div class="col-md-6">
                <label class="form-label">Email <span class="text-danger">*</span></label>
                <input type="email" class="form-control" @bind="r.Email" />
            </div>
            <div class="col-md-6">
                <label class="form-label">Phone</label>
                <input type="tel" class="form-control" @bind="r.Phone" />
            </div>
        </div>
    </div>
}

@if (References.Count < 3)
{
    <button class="btn btn-outline-secondary btn-sm mb-3" @onclick="AddReference">
        + Add Reference
    </button>
}

@if (!string.IsNullOrEmpty(ValidationError))
{
    <div class="alert alert-danger py-2">@ValidationError</div>
}

<div class="d-flex justify-content-between">
    <button class="btn btn-outline-secondary" @onclick="OnBack">← Back</button>
    <button class="btn btn-primary" @onclick="OnNext">Next →</button>
</div>

@code {
    [Parameter, EditorRequired] public List<ReferenceModel> References { get; set; } = new();
    [Parameter] public string? ValidationError { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }
    [Parameter] public EventCallback OnNext { get; set; }

    private void AddReference() { if (References.Count < 3) References.Add(new ReferenceModel()); }
    private void RemoveReference(int index) => References.RemoveAt(index);
}

@using sv_67b0a31f79bf45758e9a29e245d4ebb7.Components.Pages.ApplySteps

<h4 class="card-title mb-3">Cover Letter</h4>

<div class="mb-3">
    <textarea class="form-control" rows="12"
              value="@CoverLetter"
              @oninput="HandleInput"
              maxlength="2000"></textarea>
    <div class="form-text text-end">@(CoverLetter?.Length ?? 0) / 2000 characters</div>
</div>

@if (!string.IsNullOrEmpty(ValidationError))
{
    <div class="alert alert-danger py-2">@ValidationError</div>
}

<div class="d-flex justify-content-between">
    <button class="btn btn-outline-secondary" @onclick="OnBack">← Back</button>
    <button class="btn btn-primary" @onclick="OnNext">Next →</button>
</div>

@code {
    [Parameter] public string CoverLetter { get; set; } = "";
    [Parameter] public EventCallback<string> CoverLetterChanged { get; set; }
    [Parameter] public string? ValidationError { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }
    [Parameter] public EventCallback OnNext { get; set; }

    private async Task HandleInput(ChangeEventArgs e)
    {
        var value = e.Value?.ToString() ?? "";
        if (value.Length > 2000) value = value[..2000];
        await CoverLetterChanged.InvokeAsync(value);
    }
}

